```shell
cargo new partial-match-query && cd partial-match-query
```From the `src` directory of your project, create a file called `main.rs`.The following code example performs the following tasks:* Imports `mongodb`, the MongoDB Rust Driver.

* Creates a `Client` instance to establish a
  connection to your cluster.

* Runs a query that uses:

  - [$search](pipe.$search) stage to look for a term

  - [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to 5 results

  - [$project](manual/reference/operator/aggregation/project) stage to exclude all fields except `title`
    and `plot`

* Iterates over the cursor to print the documents that match the
  query.autocompleteThe query allows the following for matching the query string `new
purchase` to a word in the field:* Allows the words `new` and `purchase` to appear anywhere in the
  `plot` field.

* Allows two character variation in the query string to match the
  query to a word in the field, but doesn't allow the first character
  in the query string to change.

* Allows up to two hundred and fifty six similar terms to be
  considered.```rust
use mongodb::bson::{doc, DateTime, from_document};
use mongodb::{Client, Collection};
use serde::{Deserialize, Serialize};
use futures::TryStreamExt;

#[derive(Debug, Deserialize, Serialize)]
struct Movie {
    title: Option<String>,
    plot: Option<String>,
    genres: Option<Vec<String>>,
    released: Option<DateTime>,
}

#[tokio::main]
async fn main() -> mongodb::error::Result<()> {
    let uri = "<connection-string>";
    let client = Client::with_uri_str(uri).await?;

let agg = vec![
        doc! {
            "$search": {
                "index": "partial-match-tutorial",
                "autocomplete": {
                    "path": "plot",
                    "query": "new purchase",
                    "tokenOrder": "any",
                    "fuzzy": {
                        "maxEdits": 2,
                        "prefixLength": 1,
                        "maxExpansions": 256
                    }
                },
                "highlight": {
                    "path": "plot"
                }
            }
        },
        doc! {
            "$limit": 5
        },
        doc! {
            "$project": {
                "_id": 0,
                "title": 1,
                "plot": 1,
                "highlights": {
                    "$meta": "searchHighlights"
                }
            }
        }
    ];

    let coll: Collection<Movie> = client
        .database("sample_mflix")
        .collection("movies");
    while let Some(doc) = result.try_next().await? {
        let movie: Movie = from_document(doc)?;
        println!("  Title: {}", movie.title.unwrap_or_else(|| "N/A".to_string()));
        println!("  Plot: {}", movie.plot.unwrap_or_else(|| "N/A".to_string()));
        println!();
    }

    Ok(())
}
